            let err_val = self.get_at(func);
            self.set_top(func);
            Err(LuaError::Syntax(err_val))
        }
        LuaStatus::Yield => {
            self.set_top(func);
            Err(LuaError::Yield)
        }
        _ => {
            let err_val = self.get_at(func);
            self.set_top(func);
            Err(LuaError::Runtime(err_val))
        }
    }
}
