                        let v2 = state.get_at(base + i.arg_c()).clone();
                        bitwise_shift_rr(state, ra, &v1, &v2, &mut pc, true);
                    }
                    // C: op_bitwise(L, luaV_shiftl)
                    OpCode::Shl => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
