                        if (cond as i32) != i.arg_k() {
                            pc += 1;
                        } else {
                            let next = state.proto_code(&cl, pc);
                            pc = (pc as i64 + next.arg_s_j() as i64 + 1) as u32;
                            trap = state.ci_trap(ci);
