                    // ── OP_TESTSET ─────────────────────────────────────────────
                    // C: if (l_isfalse(rb) == GETARG_k(i)) pc++;
                    //    else { setobj2s(L, ra, rb); donextjump(ci); }
                    OpCode::TestSet => {
