                            let ci_top = state.ci_top(ci);
                            if state.top_idx().0 < ci_top.0 {
                                state.set_top(ci_top);
                            }
                            state.close_upvals(base)?;
                            trap = state.ci_trap(ci);
                            base = state.ci_base(ci); // updatestack
                        }
