                            state.set_top(ra);
                            state.set_ci_savedpc(ci, pc);
                            state.poscall(ci, 0)?;
                            trap = true;
                        } else {
                            let nres = state.ci_nresults(ci);
                            state.set_ci_previous(ci);
                            state.set_top(base - 1);
                            for _ in 0..nres.max(0) {
